// ── HTML cache ────────────────────────────────────────────────────────────
let _cachedHtml = null;

function getHTML() {
  if (_cachedHtml) return _cachedHtml;
  const b64 = CHUNKS.join('');
  const binary = atob(b64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
  let html = new TextDecoder('utf-8').decode(bytes);

  // Inject owner-scoped sync calls into the embedded app so every browser
  // gets an isolated R2 namespace without requiring a separate frontend build.
  if (!html.includes('function _rvOwnerId(')) {
    const helperAnchor = 'function cloudAppReady(){ return false; }';
    const ownerHelper = "function _rvNormalizeOwner(v){ return String(v||'').trim().replace(/[^a-zA-Z0-9._-]/g,'').slice(0,128); }\nfunction _rvOwnerId(){ const k='rv-owner-id'; let v=_rvNormalizeOwner(localStorage.getItem(k)); if(!v){ v='u_'+Math.random().toString(36).slice(2)+Date.now().toString(36); localStorage.setItem(k,v); } return v; }\nfunction _rvSetOwnerId(v){ const id=_rvNormalizeOwner(v); if(!id) return null; localStorage.setItem('rv-owner-id',id); return id; }\nfunction _rvInitOwnerControls(){ const r2Input=document.getElementById('r2UrlInput'); if(!r2Input||document.getElementById('rvOwnerInput')) return; const row=document.createElement('div'); row.style.display='grid'; row.style.gridTemplateColumns='1fr auto'; row.style.gap='8px'; row.style.marginTop='8px'; const input=document.createElement('input'); input.id='rvOwnerInput'; input.type='text'; input.placeholder='Shared Sync Owner ID'; input.value=_rvOwnerId(); input.autocomplete='off'; input.spellcheck=false; input.style.padding='8px'; input.style.borderRadius='8px'; input.style.border='1px solid var(--line)'; input.style.background='var(--s2)'; input.style.color='var(--text)'; const btn=document.createElement('button'); btn.type='button'; btn.className='btn sm'; btn.textContent='Save Owner'; btn.onclick=()=>{ const saved=_rvSetOwnerId(input.value); if(!saved){ toast('Enter a valid Owner ID (letters, numbers, . _ -)','err'); return; } input.value=saved; toast('Owner ID saved: '+saved); }; row.appendChild(input); row.appendChild(btn); const note=document.createElement('div'); note.style.fontSize='11px'; note.style.color='var(--muted)'; note.style.marginTop='6px'; note.textContent='Use this same Owner ID on each device to sync your own ROM uploads only.'; const host=r2Input.parentElement||r2Input; host.appendChild(row); host.appendChild(note); }\nif(document.readyState==='loading') document.addEventListener('DOMContentLoaded',_rvInitOwnerControls); else setTimeout(_rvInitOwnerControls,0);\n";
    if (html.includes(helperAnchor)) {
      html = html.replace(helperAnchor, ownerHelper + helperAnchor);
    }
  }

  if (!html.includes('function _rvOwnerFromInput(') && html.includes('function _rvOwnerId(')) {
    const helperAnchor = 'function cloudAppReady(){ return false; }';
    const ownerInputBridge = "function _rvOwnerFromInput(){ const el=document.getElementById('rvOwnerInput'); if(!el) return ''; const v=_rvNormalizeOwner(el.value); if(!v) return ''; localStorage.setItem('rv-owner-id',v); return v; }\nconst __rvOwnerIdOriginal=_rvOwnerId; _rvOwnerId=function(){ return _rvOwnerFromInput() || __rvOwnerIdOriginal(); };\n";
    if (html.includes(helperAnchor)) {
      html = html.replace(helperAnchor, helperAnchor + ownerInputBridge);
    }
  }

  if (!html.includes('function _rvSessionPassword(')) {
    const helperAnchor = 'function cloudAppReady(){ return false; }';
    const sessionHelper = "function _rvNormalizeSessionPassword(v){ return String(v||'').trim().slice(0,64); }\nfunction _rvSessionPassword(){ return _rvNormalizeSessionPassword(localStorage.getItem('rv-session-password')); }\nfunction _rvSetSessionPassword(v){ const clean=_rvNormalizeSessionPassword(v); if(clean.length<4){ return null; } localStorage.setItem('rv-session-password', clean); return clean; }\nfunction _rvSessionStatus(msg, state){ const el=document.getElementById('rvSessionStatus'); if(el){ el.textContent=msg; el.style.color=state==='err'?'#ff5555':'var(--muted)'; } if(typeof toast==='function'){ if(state==='err') toast(msg,'err'); else toast(msg); } }\nasync function _rvCreateSession(){ const password=_rvSessionPassword(); if(password.length<4){ _rvSessionStatus('Set an Online Session password first (min 4 chars).','err'); return; } try{ const resp=await fetch(window.location.origin+'/session-create',{ method:'POST', headers:{'Content-Type':'application/json'}, body:JSON.stringify({ password, hostName:(typeof _rvOwnerId==='function'?_rvOwnerId():'host') }) }); const data=await resp.json(); if(!resp.ok||!data.ok) throw new Error(data.error||('HTTP '+resp.status)); localStorage.setItem('rv-last-session-id', data.sessionId); if(navigator.clipboard&&navigator.clipboard.writeText){ navigator.clipboard.writeText(data.sessionId).catch(()=>{}); } _rvSessionStatus('Session created: '+data.sessionId+' (copied to clipboard)','ok'); }catch(e){ _rvSessionStatus('Create session failed: '+e.message,'err'); } }\nasync function _rvJoinSession(){ const password=_rvSessionPassword(); if(password.length<4){ _rvSessionStatus('Set an Online Session password first (min 4 chars).','err'); return; } const prev=localStorage.getItem('rv-last-session-id')||''; const sessionId=String(prompt('Enter session code',prev)||'').trim(); if(!sessionId){ return; } try{ const resp=await fetch(window.location.origin+'/session-join',{ method:'POST', headers:{'Content-Type':'application/json'}, body:JSON.stringify({ sessionId, password, playerName:(typeof _rvOwnerId==='function'?_rvOwnerId():'player') }) }); const data=await resp.json(); if(!resp.ok||!data.ok) throw new Error(data.error||('HTTP '+resp.status)); localStorage.setItem('rv-last-session-id', sessionId); _rvSessionStatus('Joined session '+sessionId+' ('+(data.memberCount||0)+' players)','ok'); }catch(e){ _rvSessionStatus('Join failed: '+e.message,'err'); } }\nfunction _rvInitSessionControls(){ const r2Input=document.getElementById('r2UrlInput'); if(!r2Input||document.getElementById('rvSessionPasswordInput')) return; const host=r2Input.parentElement||r2Input; const card=document.createElement('div'); card.style.marginTop='12px'; card.style.padding='10px'; card.style.border='1px solid var(--line)'; card.style.borderRadius='10px'; card.style.background='var(--s2)'; const title=document.createElement('div'); title.style.fontWeight='700'; title.style.marginBottom='8px'; title.textContent='Online Session'; const row=document.createElement('div'); row.style.display='grid'; row.style.gridTemplateColumns='1fr auto'; row.style.gap='8px'; const input=document.createElement('input'); input.id='rvSessionPasswordInput'; input.type='password'; input.placeholder='Session password (share only with friends)'; input.value=_rvSessionPassword(); input.autocomplete='off'; input.style.padding='8px'; input.style.borderRadius='8px'; input.style.border='1px solid var(--line)'; input.style.background='var(--s1)'; input.style.color='var(--text)'; const saveBtn=document.createElement('button'); saveBtn.type='button'; saveBtn.className='btn sm'; saveBtn.textContent='Save Password'; saveBtn.onclick=()=>{ const saved=_rvSetSessionPassword(input.value); if(!saved){ _rvSessionStatus('Password must be at least 4 characters.','err'); return; } input.value=saved; _rvSessionStatus('Session password saved.','ok'); }; row.appendChild(input); row.appendChild(saveBtn); const actions=document.createElement('div'); actions.style.display='flex'; actions.style.gap='8px'; actions.style.marginTop='8px'; const createBtn=document.createElement('button'); createBtn.type='button'; createBtn.className='btn sm'; createBtn.textContent='Create Session'; createBtn.onclick=_rvCreateSession; const joinBtn=document.createElement('button'); joinBtn.type='button'; joinBtn.className='btn sm'; joinBtn.textContent='Join Session'; joinBtn.onclick=_rvJoinSession; actions.appendChild(createBtn); actions.appendChild(joinBtn); const note=document.createElement('div'); note.style.fontSize='11px'; note.style.color='var(--muted)'; note.style.marginTop='6px'; note.textContent='Only users with the same session code + password can join. Gameplay net-sync must still be integrated separately.'; const status=document.createElement('div'); status.id='rvSessionStatus'; status.style.fontSize='11px'; status.style.color='var(--muted)'; status.style.marginTop='6px'; status.textContent='Set your password, then create or join a private session.'; card.appendChild(title); card.appendChild(row); card.appendChild(actions); card.appendChild(note); card.appendChild(status); host.appendChild(card); }\nif(document.readyState==='loading') document.addEventListener('DOMContentLoaded',_rvInitSessionControls); else setTimeout(_rvInitSessionControls,0);\n";
    if (html.includes(helperAnchor)) {
      html = html.replace(helperAnchor, sessionHelper + helperAnchor);
    }
  }

  if (!html.includes('function _rvMigrateLegacyBucket(')) {
    const helperAnchor = 'function cloudAppReady(){ return false; }';
    const migrateHelper = "function _rvMigrationStatus(msg,state){ const el=document.getElementById('rvMigrationStatus'); if(el){ el.textContent=msg; el.style.color=state==='err'?'#ff5555':(state==='ok'?'var(--green)':'var(--muted)'); } if(typeof toast==='function'){ if(state==='err') toast(msg,'err'); else toast(msg); } }\nasync function _rvMigrateLegacyBucket(dryRun){ const owner=(typeof _rvOwnerId==='function'?_rvOwnerId():''); if(!owner){ _rvMigrationStatus('Set Shared Sync Owner ID first.','err'); return; } if(!dryRun){ const yes=confirm('Migrate legacy bucket ROMs into users/'+owner+'/? This will move old root ROM keys so sync can see them again.'); if(!yes) return; } _rvMigrationStatus((dryRun?'Previewing':'Migrating')+' legacy bucket keys…',''); try{ const resp=await fetch(window.location.origin+'/r2-migrate-owner',{ method:'POST', headers:{'Content-Type':'application/json'}, body:JSON.stringify({ owner, dryRun:!!dryRun, removeLegacy:true }) }); const data=await resp.json(); if(!resp.ok||!data.ok) throw new Error(data.error||('HTTP '+resp.status)); const msg=(dryRun?'Preview':'Migration')+': '+(data.migratable||0)+' eligible, '+(data.migrated||0)+' copied, '+(data.deleted||0)+' moved, '+(data.failed||0)+' failed.'; _rvMigrationStatus(msg,'ok'); }catch(e){ _rvMigrationStatus('Legacy migration failed: '+e.message,'err'); } }\nfunction _rvInitMigrationControls(){ const ownerInput=document.getElementById('rvOwnerInput'); if(!ownerInput||document.getElementById('rvMigrateLegacyBtn')) return; const host=(ownerInput.parentElement&&ownerInput.parentElement.parentElement)||ownerInput.parentElement||ownerInput; const wrap=document.createElement('div'); wrap.style.display='flex'; wrap.style.gap='8px'; wrap.style.marginTop='8px'; const previewBtn=document.createElement('button'); previewBtn.type='button'; previewBtn.className='btn sm'; previewBtn.textContent='Preview Legacy Migration'; previewBtn.onclick=()=>_rvMigrateLegacyBucket(true); const migrateBtn=document.createElement('button'); migrateBtn.type='button'; migrateBtn.className='btn sm'; migrateBtn.id='rvMigrateLegacyBtn'; migrateBtn.textContent='Migrate Existing ROMs'; migrateBtn.onclick=()=>_rvMigrateLegacyBucket(false); wrap.appendChild(previewBtn); wrap.appendChild(migrateBtn); const note=document.createElement('div'); note.style.fontSize='11px'; note.style.color='var(--muted)'; note.style.marginTop='6px'; note.textContent='Use once if your old bucket ROMs were uploaded before owner-scoped sync was enabled.'; const status=document.createElement('div'); status.id='rvMigrationStatus'; status.style.fontSize='11px'; status.style.color='var(--muted)'; status.style.marginTop='6px'; status.textContent='Legacy migration not run yet.'; host.appendChild(wrap); host.appendChild(note); host.appendChild(status); }\nif(document.readyState==='loading') document.addEventListener('DOMContentLoaded',_rvInitMigrationControls); else setTimeout(_rvInitMigrationControls,0);\n";
    if (html.includes(helperAnchor)) {
      html = html.replace(helperAnchor, migrateHelper + helperAnchor);
    }
  }

  html = html
    .replace(
      "formData.append('key', key);",
      "formData.append('key', key); formData.append('owner', _rvOwnerId());"
    )
    .replace(
      "body: JSON.stringify({ key, meta: payload }),",
      "body: JSON.stringify({ key, meta: payload, owner: _rvOwnerId() }),"
    )
    .replace(
      "fetch(window.location.origin+'/r2-list');",
      "fetch(window.location.origin+'/r2-list?owner='+encodeURIComponent(_rvOwnerId()));"
    )
    .replace(
      "fetch(window.location.origin+'/r2-meta-list');",
      "fetch(window.location.origin+'/r2-meta-list?owner='+encodeURIComponent(_rvOwnerId()));"
    )
    .replace(
      "      const parts = obj.key.split('/');\n      if(parts.length < 2) continue;\n      // Support both {console}/{file} and {prefix}/{console}/{file} layouts\n      let consoleId, filename;\n      const s0 = getSys(parts[0]);\n      if(s0 && s0.ejsSys){\n        // Direct layout: nes/game.nes\n        consoleId = parts[0];\n        filename = parts.slice(1).join('/');\n      } else if(parts.length >= 3 && getSys(parts[1])?.ejsSys){\n        // Prefixed layout: game-roms/nes/game.nes\n        consoleId = parts[1];\n        filename = parts.slice(2).join('/');\n      } else {\n        continue; // can't identify console — skip\n      }\n",
      "      const parts = obj.key.split('/').filter(Boolean);\n      if(parts.length < 2) continue;\n      // Accept nested layouts like users/main/nes/game.nes by locating\n      // the first path segment that maps to a known console id.\n      let consoleIndex = -1;\n      for(let i=0; i<parts.length-1; i++){\n        const candidate = getSys(parts[i]);\n        if(candidate && candidate.ejsSys){\n          consoleIndex = i;\n          break;\n        }\n      }\n      if(consoleIndex === -1) continue;\n      const consoleId = parts[consoleIndex];\n      const filename = parts.slice(consoleIndex + 1).join('/');\n      if(!filename) continue;\n"
    )
    .replace(
      "return { publicUrl, fullPath: key };",
      "return { publicUrl, fullPath: result.key || key };"
    );

  _cachedHtml = html;
  return _cachedHtml;
}

// ── CORS headers ──────────────────────────────────────────────────────────
function corsHeaders(origin) {
  return {
    'Access-Control-Allow-Origin': origin || '*',
    'Access-Control-Allow-Methods': 'GET, POST, PUT, DELETE, OPTIONS',
    'Access-Control-Allow-Headers': 'Content-Type, Authorization, X-File-Name, X-Requested-With, X-Retrovault-Owner, X-Retrovault-User, X-User-Id',
    'Access-Control-Max-Age': '86400',
  };
}

function sanitizeOwnerId(value) {
  if (value == null) return null;
  const cleaned = String(value).trim().replace(/[^a-zA-Z0-9._-]/g, '');
  if (!cleaned) return null;
  return cleaned.slice(0, 128);
}

function resolveOwnerId(request, url, fallbackValues = []) {
  const headerOrQueryOwner = sanitizeOwnerId(
    request.headers.get('X-Retrovault-Owner')
      || request.headers.get('X-Retrovault-User')
      || request.headers.get('X-User-Id')
      || url.searchParams.get('owner')
      || url.searchParams.get('user')
  );
  if (headerOrQueryOwner) return headerOrQueryOwner;
  for (const value of fallbackValues) {
    const ownerId = sanitizeOwnerId(value);
    if (ownerId) return ownerId;
  }
  return null;
}

function ownerPrefix(ownerId) {
  return `users/${ownerId}/`;
}

function normalizeR2Key(rawKey) {
  return String(rawKey || '').replace(/\.\./g, '').replace(/^\/+/, '');
}

function toOwnedKey(rawKey, ownerId) {
  const key = normalizeR2Key(rawKey);
  if (!key) return null;
  const prefix = ownerPrefix(ownerId);
  if (key.startsWith('users/')) {
    if (!key.startsWith(prefix)) return null;
    return key;
  }
  return prefix + key;
}

function isGlobalUnscopedKey(key) {
  const normalized = normalizeR2Key(key);
  return normalized.startsWith('bios/')
    || normalized === 'meta/lb_index.json.gz'
    || normalized === 'meta/lb_index.json';
}

function sanitizeSessionId(value) {
  const cleaned = String(value || '').trim().replace(/[^a-zA-Z0-9_-]/g, '').slice(0, 40);
  return cleaned || null;
}

function sanitizeSessionName(value, fallback) {
  const cleaned = String(value || '').trim().replace(/[<>]/g, '').slice(0, 40);
  return cleaned || fallback;
}

function randomToken(length = 12) {
  const alphabet = 'abcdefghijklmnopqrstuvwxyz0123456789';
  const bytes = new Uint8Array(length);
  crypto.getRandomValues(bytes);
  let out = '';
  for (let i = 0; i < length; i++) {
    out += alphabet[bytes[i] % alphabet.length];
  }
  return out;
}

async function sha256Hex(text) {
  const data = new TextEncoder().encode(String(text || ''));
  const hash = await crypto.subtle.digest('SHA-256', data);
  const bytes = new Uint8Array(hash);
  let out = '';
  for (const b of bytes) out += b.toString(16).padStart(2, '0');
  return out;
}

function buildSessionPublic(session) {
  const members = Array.isArray(session.members) ? session.members : [];
  return {
    sessionId: session.sessionId,
    roomName: session.roomName,
    createdAt: session.createdAt || Date.now(),
    updatedAt: session.updatedAt || Date.now(),
    maxPlayers: session.maxPlayers || 4,
    memberCount: members.length,
    members: members.map(m => ({
      memberId: m.memberId,
      name: m.name,
      role: m.role || 'player',
      joinedAt: m.joinedAt || Date.now(),
      lastSeenAt: m.lastSeenAt || m.joinedAt || Date.now(),
    })),
  };
}

function normalizeSessionPassword(value) {
  return String(value || '').trim().slice(0, 64);
}

function sessionStorageKey(sessionId) {
  return `meta/sessions/${sessionId}.json`;
}

async function loadSessionFromR2(bucket, sessionId) {
  const obj = await bucket.get(sessionStorageKey(sessionId));
  if (!obj) return null;
  const text = await obj.text();
  return JSON.parse(text);
}

async function saveSessionToR2(bucket, session) {
  await bucket.put(sessionStorageKey(session.sessionId), JSON.stringify(session), {
    httpMetadata: { contentType: 'application/json' },
  });
}

async function isValidSessionPassword(session, password) {
  const normalized = normalizeSessionPassword(password);
  if (normalized.length < 4) return false;
  if (!session || !session.passwordHash) return false;
  if (session.passwordSalt) {
    const hash = await sha256Hex(`${session.passwordSalt}:${normalized}`);
    return hash === session.passwordHash;
  }
  const legacyHash = await sha256Hex(normalized);
  return legacyHash === session.passwordHash;
}

function sanitizeMaxPlayers(value) {
  const parsed = Number(value);
  if (!Number.isFinite(parsed)) return 4;
  return Math.max(2, Math.min(16, Math.floor(parsed)));
}

function isLegacyRomKey(key) {
  const normalized = normalizeR2Key(key);
  if (!normalized) return false;
  if (normalized.startsWith('users/')) return false;
  if (normalized.startsWith('bios/')) return false;
  if (normalized.startsWith('meta/')) return false;
  if (normalized.startsWith('tmp/')) return false;
  return normalized.includes('/');
}

function migrateLegacyObjectKey(key, ownerId) {
  const normalized = normalizeR2Key(key);
  if (!isLegacyRomKey(normalized)) return null;
  return ownerPrefix(ownerId) + normalized;
}

function migrateLegacyMetaKey(key, ownerId) {
  const normalized = normalizeR2Key(key);
  if (!normalized.startsWith('meta/')) return null;
  if (normalized === 'meta/lb_index.json' || normalized === 'meta/lb_index.json.gz') return null;
  return ownerPrefix(ownerId) + normalized;
}

async function listAllObjects(bucket, options = {}) {
  const all = [];
  let cursor;
  for (let i = 0; i < 50; i++) {
    const listed = await bucket.list({ ...options, limit: 1000, cursor });
    all.push(...(listed.objects || []));
    if (!listed.truncated) break;
    cursor = listed.cursor;
    if (!cursor) break;
  }
  return all;
}

function isLegacyMigratableKey(key) {
  const normalized = normalizeR2Key(key);
  if (!normalized) return false;
  if (normalized.startsWith('users/')) return false;
  if (normalized.startsWith('bios/')) return false;
  if (normalized === 'meta/lb_index.json.gz' || normalized === 'meta/lb_index.json') return false;
  if (normalized.startsWith('meta/sessions/')) return false;
  return true;
}

function legacyDestinationKey(ownerId, sourceKey) {
  const normalized = normalizeR2Key(sourceKey);
  if (!isLegacyMigratableKey(normalized)) return null;
  return ownerPrefix(ownerId) + normalized;
}

// ── Main fetch handler ─────────────────────────────────────────────────────
export default {
  async fetch(request, env) {
    const url = new URL(request.url);
    const origin = request.headers.get('Origin') || '*';
    const method = request.method;
    const path = url.pathname;

    // CORS pre-flight
    if (method === 'OPTIONS') {
      return new Response(null, { status: 204, headers: corsHeaders(origin) });
    }

    // ════════════════════════════════════════════════════════════════════
    // ONLINE SESSIONS — private password-protected room metadata
    // Note: this stores room membership/state only. Netplay transport still
    // needs to be wired separately in emulator runtime.
    // ════════════════════════════════════════════════════════════════════
    if (path === '/session-create' && method === 'POST') {
      if (!env.ROM_BUCKET) {
        return new Response(JSON.stringify({ ok: false, error: 'ROM_BUCKET not configured' }), {
          status: 503, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' }
        });
      }
      try {
        const body = await request.json();
        const password = normalizeSessionPassword(body.password);
        if (password.length < 4) {
          return new Response(JSON.stringify({ ok: false, error: 'Password must be at least 4 characters.' }), {
            status: 400, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' }
          });
        }

        const hostName = sanitizeSessionName(body.hostName, 'Host');
        const roomName = sanitizeSessionName(body.roomName, `${hostName}'s Room`);
        const maxPlayers = sanitizeMaxPlayers(body.maxPlayers);
        const now = Date.now();

        let sessionId = null;
        for (let i = 0; i < 5; i++) {
          const candidate = randomToken(8);
          const existing = await loadSessionFromR2(env.ROM_BUCKET, candidate);
          if (!existing) {
            sessionId = candidate;
            break;
          }
        }
        if (!sessionId) {
          return new Response(JSON.stringify({ ok: false, error: 'Failed to allocate session id. Try again.' }), {
            status: 500, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' }
          });
        }

        const hostMember = {
          memberId: randomToken(12),
          name: hostName,
          role: 'host',
          joinedAt: now,
          lastSeenAt: now,
        };
        const passwordSalt = randomToken(16);
        const passwordHash = await sha256Hex(`${passwordSalt}:${password}`);
        const session = {
          sessionId,
          roomName,
          createdAt: now,
          updatedAt: now,
          maxPlayers,
          passwordSalt,
          passwordHash,
          members: [hostMember],
        };
        await saveSessionToR2(env.ROM_BUCKET, session);
        return new Response(JSON.stringify({
          ok: true,
          sessionId,
          memberId: hostMember.memberId,
          session: buildSessionPublic(session),
        }), {
          status: 200, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' }
        });
      } catch (err) {
        return new Response(JSON.stringify({ ok: false, error: 'Create session failed: ' + err.message }), {
          status: 500, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' }
        });
      }
    }

    if (path === '/session-join' && method === 'POST') {
      if (!env.ROM_BUCKET) {
        return new Response(JSON.stringify({ ok: false, error: 'ROM_BUCKET not configured' }), {
          status: 503, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' }
        });
      }
      try {
        const body = await request.json();
        const sessionId = sanitizeSessionId(body.sessionId);
        if (!sessionId) {
          return new Response(JSON.stringify({ ok: false, error: 'Missing or invalid sessionId.' }), {
            status: 400, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' }
          });
        }
        const session = await loadSessionFromR2(env.ROM_BUCKET, sessionId);
        if (!session) {
          return new Response(JSON.stringify({ ok: false, error: 'Session not found.' }), {
            status: 404, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' }
          });
        }
        const validPassword = await isValidSessionPassword(session, body.password);
        if (!validPassword) {
          return new Response(JSON.stringify({ ok: false, error: 'Invalid session password.' }), {
            status: 403, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' }
          });
        }

        const maxPlayers = sanitizeMaxPlayers(session.maxPlayers);
        session.maxPlayers = maxPlayers;
        session.members = Array.isArray(session.members) ? session.members : [];
        if (session.members.length >= maxPlayers) {
          return new Response(JSON.stringify({ ok: false, error: 'Session is full.' }), {
            status: 409, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' }
          });
        }

        const now = Date.now();
        const member = {
          memberId: randomToken(12),
          name: sanitizeSessionName(body.playerName, 'Player'),
          role: 'player',
          joinedAt: now,
          lastSeenAt: now,
        };
        session.members.push(member);
        session.updatedAt = now;
        await saveSessionToR2(env.ROM_BUCKET, session);

        return new Response(JSON.stringify({
          ok: true,
          sessionId,
          memberId: member.memberId,
          memberCount: session.members.length,
          session: buildSessionPublic(session),
        }), {
          status: 200, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' }
        });
      } catch (err) {
        return new Response(JSON.stringify({ ok: false, error: 'Join session failed: ' + err.message }), {
          status: 500, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' }
        });
      }
    }

    if (path === '/session-get') {
      if (!env.ROM_BUCKET) {
        return new Response(JSON.stringify({ ok: false, error: 'ROM_BUCKET not configured' }), {
          status: 503, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' }
        });
      }
      try {
        const sessionId = sanitizeSessionId(url.searchParams.get('sessionId'));
        const password = url.searchParams.get('password') || '';
        if (!sessionId) {
          return new Response(JSON.stringify({ ok: false, error: 'Missing sessionId.' }), {
            status: 400, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' }
          });
        }
        const session = await loadSessionFromR2(env.ROM_BUCKET, sessionId);
        if (!session) {
          return new Response(JSON.stringify({ ok: false, error: 'Session not found.' }), {
            status: 404, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' }
          });
        }
        const validPassword = await isValidSessionPassword(session, password);
        if (!validPassword) {
          return new Response(JSON.stringify({ ok: false, error: 'Invalid session password.' }), {
            status: 403, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' }
          });
        }
        return new Response(JSON.stringify({ ok: true, session: buildSessionPublic(session) }), {
          status: 200, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' }
        });
      } catch (err) {
        return new Response(JSON.stringify({ ok: false, error: 'Get session failed: ' + err.message }), {
          status: 500, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' }
        });
      }
    }

    if (path === '/session-leave' && method === 'POST') {
      if (!env.ROM_BUCKET) {
        return new Response(JSON.stringify({ ok: false, error: 'ROM_BUCKET not configured' }), {
          status: 503, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' }
        });
      }
      try {
        const body = await request.json();
        const sessionId = sanitizeSessionId(body.sessionId);
        const memberId = sanitizeSessionId(body.memberId);
        if (!sessionId || !memberId) {
          return new Response(JSON.stringify({ ok: false, error: 'Missing sessionId/memberId.' }), {
            status: 400, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' }
          });
        }
        const session = await loadSessionFromR2(env.ROM_BUCKET, sessionId);
        if (!session) {
          return new Response(JSON.stringify({ ok: false, error: 'Session not found.' }), {
            status: 404, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' }
          });
        }
        const validPassword = await isValidSessionPassword(session, body.password);
        if (!validPassword) {
          return new Response(JSON.stringify({ ok: false, error: 'Invalid session password.' }), {
            status: 403, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' }
          });
        }
        const before = Array.isArray(session.members) ? session.members.length : 0;
        session.members = (session.members || []).filter(m => m.memberId !== memberId);
        if (session.members.length === before) {
          return new Response(JSON.stringify({ ok: false, error: 'Member not found in session.' }), {
            status: 404, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' }
          });
        }
        session.updatedAt = Date.now();
        if (!session.members.length) {
          await env.ROM_BUCKET.delete(sessionStorageKey(sessionId));
          return new Response(JSON.stringify({ ok: true, removed: true, memberCount: 0 }), {
            status: 200, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' }
          });
        }
        await saveSessionToR2(env.ROM_BUCKET, session);
        return new Response(JSON.stringify({ ok: true, memberCount: session.members.length, session: buildSessionPublic(session) }), {
          status: 200, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' }
        });
      } catch (err) {
        return new Response(JSON.stringify({ ok: false, error: 'Leave session failed: ' + err.message }), {
          status: 500, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' }
        });
      }
    }

    // ════════════════════════════════════════════════════════════════════
    // R2 UPLOAD — POST /r2-upload (FormData) | PUT /r2-upload/{key} (binary)
    // ════════════════════════════════════════════════════════════════════
    if (path === '/r2-upload' || path.startsWith('/r2-upload/')) {

      if (!env.ROM_BUCKET) {
        return new Response(
          JSON.stringify({ ok: false, error: 'ROM_BUCKET R2 binding not configured. Go to Cloudflare Dashboard → Workers → retrovault → Settings → Bindings → Add R2 binding: ROM_BUCKET → your bucket name' }),
          { status: 503, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' } }
        );
      }

      // GET /r2-upload → ping/status
      if (method === 'GET') {
        return new Response(
          JSON.stringify({ ok: true, r2: 'configured', binding: 'ROM_BUCKET' }),
          { status: 200, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' } }
        );
      }

      // POST /r2-upload — FormData
      if (method === 'POST') {
        try {
          let key, fileData, contentType;
          const ct = request.headers.get('Content-Type') || '';
          let ownerId = resolveOwnerId(request, url);

          if (ct.includes('multipart/form-data')) {
            const formData = await request.formData();
            const file = formData.get('file');
            key = formData.get('key') || (file ? file.name : null);
            ownerId = ownerId || resolveOwnerId(request, url, [formData.get('owner'), formData.get('user'), formData.get('userId')]);
            if (!file) return new Response(JSON.stringify({ ok: false, error: 'No file in FormData' }), { status: 400, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' } });
            fileData = await file.arrayBuffer();
            contentType = file.type || 'application/octet-stream';
          } else if (ct.includes('application/json')) {
            const body = await request.json();
            key = body.key;
            ownerId = ownerId || resolveOwnerId(request, url, [body.owner, body.user, body.userId, body.ownerId]);
            fileData = Uint8Array.from(atob(body.data), c => c.charCodeAt(0));
            contentType = body.contentType || 'application/octet-stream';
          } else {
            key = url.searchParams.get('key') || url.searchParams.get('filename');
            fileData = await request.arrayBuffer();
            contentType = ct || 'application/octet-stream';
          }

          if (!key) return new Response(JSON.stringify({ ok: false, error: 'Missing key/filename' }), { status: 400, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' } });
          key = normalizeR2Key(key);

          if (!isGlobalUnscopedKey(key)) {
            if (!ownerId) return new Response(JSON.stringify({ ok: false, error: 'Missing owner id. Send X-Retrovault-Owner header or ?owner= in request.' }), { status: 400, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' } });
            key = toOwnedKey(key, ownerId);
            if (!key) return new Response(JSON.stringify({ ok: false, error: 'Key is outside your owner scope' }), { status: 403, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' } });
          }

          const putOptions = { httpMetadata: { contentType } };
          if (ownerId) putOptions.customMetadata = { ownerId };
          await env.ROM_BUCKET.put(key, fileData, putOptions);

          const r2PublicUrl = env.R2_PUBLIC_URL
            ? env.R2_PUBLIC_URL.replace(/\/+$/, '') + '/' + key
            : null;

          return new Response(
            JSON.stringify({ ok: true, key, url: r2PublicUrl, filename: key.split('/').pop(), message: r2PublicUrl ? 'Upload successful' : 'Upload successful. Set R2_PUBLIC_URL env var for auto URL.' }),
            { status: 200, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' } }
          );
        } catch (err) {
          return new Response(JSON.stringify({ ok: false, error: 'R2 POST upload failed: ' + err.message }), { status: 500, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' } });
        }
      }

      // PUT /r2-upload/{key} — binary
      if (method === 'PUT') {
        const ownerId = resolveOwnerId(request, url);
        let key = decodeURIComponent(path.replace('/r2-upload/', '')).replace(/\.\./g, '').replace(/^\/+/, '');
        if (!key || key === 'ping') return new Response(JSON.stringify({ ok: true, r2: 'ready' }), { status: 200, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' } });
        try {
          key = normalizeR2Key(key);
          if (!isGlobalUnscopedKey(key)) {
            if (!ownerId) return new Response(JSON.stringify({ ok: false, error: 'Missing owner id. Send X-Retrovault-Owner header or ?owner= in request.' }), { status: 400, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' } });
            key = toOwnedKey(key, ownerId);
            if (!key) return new Response(JSON.stringify({ ok: false, error: 'Key is outside your owner scope' }), { status: 403, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' } });
          }
          const body = await request.arrayBuffer();
          const contentType = request.headers.get('Content-Type') || 'application/octet-stream';
          const putOptions = { httpMetadata: { contentType } };
          if (ownerId) putOptions.customMetadata = { ownerId };
          await env.ROM_BUCKET.put(key, body, putOptions);
          const r2PublicUrl = env.R2_PUBLIC_URL ? env.R2_PUBLIC_URL.replace(/\/+$/, '') + '/' + key : null;
          return new Response(JSON.stringify({ ok: true, key, url: r2PublicUrl }), { status: 200, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' } });
        } catch (err) {
          return new Response(JSON.stringify({ ok: false, error: 'R2 PUT failed: ' + err.message }), { status: 500, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' } });
        }
      }

      // DELETE /r2-upload/{key}
      if (method === 'DELETE') {
        const ownerId = resolveOwnerId(request, url);
        let key = decodeURIComponent(path.replace('/r2-upload/', '')).replace(/\.\./g, '');
        try {
          key = normalizeR2Key(key);
          if (!isGlobalUnscopedKey(key)) {
            if (!ownerId) return new Response(JSON.stringify({ ok: false, error: 'Missing owner id. Send X-Retrovault-Owner header or ?owner= in request.' }), { status: 400, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' } });
            key = toOwnedKey(key, ownerId);
            if (!key) return new Response(JSON.stringify({ ok: false, error: 'Key is outside your owner scope' }), { status: 403, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' } });
          }
          await env.ROM_BUCKET.delete(key);
          return new Response(JSON.stringify({ ok: true }), { status: 200, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' } });
        } catch (err) {
          return new Response(JSON.stringify({ ok: false, error: err.message }), { status: 500, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' } });
        }
      }
    }

    // ════════════════════════════════════════════════════════════════════
    // ROM PROXY — GET /rom-proxy?url=   (CORS bypass for R2 ROM fetches)
    // ════════════════════════════════════════════════════════════════════
    if (path === '/rom-proxy') {
      const target = url.searchParams.get('url');
      if (!target) return new Response(JSON.stringify({ ok: false, error: 'Missing url' }), { status: 400, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' } });

      try {
        const upstream = await fetch(target);
        if (!upstream.ok) return new Response('Upstream error: ' + upstream.status, { status: upstream.status, headers: { ...corsHeaders(origin), 'Content-Type': 'text/plain' } });
        const responseHeaders = {
          ...corsHeaders(origin),
          'Content-Type': upstream.headers.get('Content-Type') || 'application/octet-stream',
          'Cache-Control': 'public, max-age=86400',
        };
        const cl = upstream.headers.get('Content-Length');
        if (cl) responseHeaders['Content-Length'] = cl;
        return new Response(upstream.body, { status: 200, headers: responseHeaders });
      } catch (err) {
        return new Response('Proxy fetch failed: ' + err.message, { status: 502, headers: { ...corsHeaders(origin), 'Content-Type': 'text/plain' } });
      }
    }


    // ════════════════════════════════════════════════════════════════════
    // R2 LIST — GET /r2-list  lists all objects in ROM_BUCKET
    // Used by the frontend Sync from Bucket feature
    // ════════════════════════════════════════════════════════════════════
    if (path === '/r2-list') {
      if (!env.ROM_BUCKET) {
        return new Response(JSON.stringify({ ok: false, error: 'ROM_BUCKET not configured' }),
          { status: 503, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' } });
      }
      try {
        const ownerId = resolveOwnerId(request, url);
        if (!ownerId) {
          return new Response(JSON.stringify({ ok: false, error: 'Missing owner id. Send X-Retrovault-Owner header or ?owner= in request.' }),
            { status: 400, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' } });
        }
        const prefix = ownerPrefix(ownerId);
        const listed = await env.ROM_BUCKET.list({ prefix, limit: 1000 });
        const objects = listed.objects
          .filter(o => !o.key.startsWith(prefix + 'bios/') && !o.key.startsWith(prefix + 'meta/'))
          .map(o => ({
            key: o.key,
            size: o.size,
            uploaded: o.uploaded,
          }));
        return new Response(JSON.stringify({ ok: true, ownerId, objects, truncated: listed.truncated }),
          { status: 200, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' } });
      } catch (err) {
        return new Response(JSON.stringify({ ok: false, error: err.message }),
          { status: 500, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' } });
      }
    }

    // ════════════════════════════════════════════════════════════════════
    // ════════════════════════════════════════════════════════════════════
    // R2 META SAVE — POST /r2-meta-save  saves a metadata sidecar JSON
    // Called after scraping to persist cover URL + metadata in R2
    // ════════════════════════════════════════════════════════════════════
    if (path === '/r2-meta-save' && method === 'POST') {
      if (!env.ROM_BUCKET) {
        return new Response(JSON.stringify({ ok: false, error: 'ROM_BUCKET not configured' }),
          { status: 503, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' } });
      }
      try {
        const body = await request.json();
        const ownerId = resolveOwnerId(request, url, [body.owner, body.user, body.userId, body.ownerId]);
        if (!ownerId) {
          return new Response(JSON.stringify({ ok: false, error: 'Missing owner id. Send X-Retrovault-Owner header or ?owner= in request.' }),
            { status: 400, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' } });
        }
        let rawKey = normalizeR2Key(body.key || '');
        if (rawKey.startsWith('meta/')) rawKey = ownerPrefix(ownerId) + rawKey;
        const key = toOwnedKey(rawKey, ownerId);
        if (!key || !key.startsWith(ownerPrefix(ownerId) + 'meta/')) {
          return new Response(JSON.stringify({ ok: false, error: 'Invalid meta key' }),
            { status: 400, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' } });
        }
        await env.ROM_BUCKET.put(key, JSON.stringify(body.meta || {}), {
          httpMetadata: { contentType: 'application/json' },
          customMetadata: { ownerId }
        });
        return new Response(JSON.stringify({ ok: true, ownerId, key }),
          { status: 200, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' } });
      } catch (err) {
        return new Response(JSON.stringify({ ok: false, error: err.message }),
          { status: 500, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' } });
      }
    }

        // R2 META LIST — GET /r2-meta-list  returns all metadata sidecar JSONs
    // Used by Sync from Bucket to restore scraped metadata on other devices
    // ════════════════════════════════════════════════════════════════════
    if (path === '/r2-meta-list') {
      if (!env.ROM_BUCKET) {
        return new Response(JSON.stringify({ ok: false, error: 'ROM_BUCKET not configured' }),
          { status: 503, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' } });
      }
      try {
        const ownerId = resolveOwnerId(request, url);
        if (!ownerId) {
          return new Response(JSON.stringify({ ok: false, error: 'Missing owner id. Send X-Retrovault-Owner header or ?owner= in request.' }),
            { status: 400, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' } });
        }
        const metaPrefix = ownerPrefix(ownerId) + 'meta/';
        const listed = await env.ROM_BUCKET.list({ prefix: metaPrefix, limit: 1000 });
        const metas = await Promise.all(
          listed.objects.map(async o => {
            try {
              const obj = await env.ROM_BUCKET.get(o.key);
              if (!obj) return null;
              const text = await obj.text();
              return JSON.parse(text);
            } catch(e) {
              return null;
            }
          })
        );
        return new Response(JSON.stringify({ ok: true, ownerId, metas: metas.filter(Boolean) }),
          { status: 200, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' } });
      } catch (err) {
        return new Response(JSON.stringify({ ok: false, error: err.message }),
          { status: 500, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' } });
      }
    }

    // ════════════════════════════════════════════════════════════════════
    // R2 LEGACY MIGRATION — POST /r2-migrate-owner
    // Moves pre-owner-scoped root keys into users/{owner}/... so modern
    // owner-scoped sync can see old ROM uploads without re-uploading.
    // ════════════════════════════════════════════════════════════════════
    if (path === '/r2-migrate-owner' && method === 'POST') {
      if (!env.ROM_BUCKET) {
        return new Response(JSON.stringify({ ok: false, error: 'ROM_BUCKET not configured' }), {
          status: 503, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' }
        });
      }
      try {
        const body = await request.json();
        const ownerId = resolveOwnerId(request, url, [body.owner, body.user, body.userId, body.ownerId]);
        if (!ownerId) {
          return new Response(JSON.stringify({ ok: false, error: 'Missing owner id. Set Shared Sync Owner ID first.' }), {
            status: 400, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' }
          });
        }
        const dryRun = !!body.dryRun;
        const removeLegacy = body.removeLegacy !== false;

        const objects = await listAllObjects(env.ROM_BUCKET);
        let migratable = 0;
        let migrated = 0;
        let deleted = 0;
        let failed = 0;
        let skippedExisting = 0;
        const errors = [];

        for (const item of objects) {
          const sourceKey = normalizeR2Key(item.key);
          const destinationKey = legacyDestinationKey(ownerId, sourceKey);
          if (!destinationKey || destinationKey === sourceKey) continue;
          migratable++;
          if (dryRun) continue;
          try {
            const existing = await env.ROM_BUCKET.head(destinationKey);
            if (existing) {
              skippedExisting++;
              if (removeLegacy) {
                await env.ROM_BUCKET.delete(sourceKey);
                deleted++;
              }
              continue;
            }

            const sourceObject = await env.ROM_BUCKET.get(sourceKey);
            if (!sourceObject) {
              failed++;
              if (errors.length < 20) errors.push(`Missing source object: ${sourceKey}`);
              continue;
            }
            const bodyBytes = await sourceObject.arrayBuffer();
            const putOptions = {};
            const sourceContentType = sourceObject.httpMetadata?.contentType || (sourceKey.endsWith('.json') ? 'application/json' : null);
            if (sourceContentType) putOptions.httpMetadata = { contentType: sourceContentType };
            putOptions.customMetadata = {
              ...(sourceObject.customMetadata || {}),
              ownerId,
            };
            await env.ROM_BUCKET.put(destinationKey, bodyBytes, putOptions);
            migrated++;

            if (removeLegacy) {
              await env.ROM_BUCKET.delete(sourceKey);
              deleted++;
            }
          } catch (err) {
            failed++;
            if (errors.length < 20) errors.push(`${sourceKey}: ${err.message}`);
          }
        }

        return new Response(JSON.stringify({
          ok: true,
          ownerId,
          dryRun,
          removeLegacy,
          scanned: objects.length,
          migratable,
          migrated,
          deleted,
          skippedExisting,
          failed,
          errors,
        }), {
          status: 200, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' }
        });
      } catch (err) {
        return new Response(JSON.stringify({ ok: false, error: 'Migration failed: ' + err.message }), {
          status: 500, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' }
        });
      }
    }

    // ════════════════════════════════════════════════════════════════════
    // SCRAPER CORS PROXY — GET/POST /scraper-proxy?url=
    // Bypasses CORS for ScreenScraper, LaunchBox, IGDB, TGDB
    // ════════════════════════════════════════════════════════════════════
    if (path === '/scraper-proxy') {
      const target = url.searchParams.get('url');
      if (!target) return new Response(JSON.stringify({ ok: false, error: 'Missing url' }), { status: 400, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' } });

      let targetUrl;
      try {
        targetUrl = new URL(target);
        if (targetUrl.protocol !== 'https:') throw new Error('HTTPS only');
      } catch {
        return new Response(JSON.stringify({ ok: false, error: 'Invalid URL — must be HTTPS' }), { status: 400, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' } });
      }

      try {
        const upstreamInit = {
          method: ['POST', 'PUT'].includes(method) ? method : 'GET',
          headers: { 'Accept': 'application/json, text/xml, */*', 'User-Agent': 'RetroVault/2.0' },
        };
        // Forward IGDB / scraper auth headers
        const fwdHeaders = ['Client-ID', 'Authorization', 'X-Mashape-Key'];
        fwdHeaders.forEach(h => { const v = request.headers.get(h); if(v) upstreamInit.headers[h] = v; });
        // Forward request headers that scrapers need (IGDB auth)
        const clientId = request.headers.get('Client-ID');
        const authHeader = request.headers.get('Authorization');
        if (clientId) upstreamInit.headers['Client-ID'] = clientId;
        if (authHeader) upstreamInit.headers['Authorization'] = authHeader;
        if (['POST', 'PUT'].includes(method)) {
          upstreamInit.body = await request.text();
          const reqCt = request.headers.get('Content-Type');
          if (reqCt) upstreamInit.headers['Content-Type'] = reqCt;
        }

        const upstream = await fetch(target, upstreamInit);
        const respText = await upstream.text();
        const upstreamCt = upstream.headers.get('Content-Type') || 'text/plain';

        return new Response(respText, {
          status: upstream.status,
          headers: { ...corsHeaders(origin), 'Content-Type': upstreamCt, 'Cache-Control': 'public, max-age=3600', 'X-Proxied-By': 'RetroVault Worker' },
        });
      } catch (err) {
        return new Response(JSON.stringify({ ok: false, error: 'Scraper proxy failed: ' + err.message }), { status: 502, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' } });
      }
    }

    // ════════════════════════════════════════════════════════════════════
    // SCRAPER TEST — GET /scraper-test
    // ════════════════════════════════════════════════════════════════════
    if (path === '/scraper-test') {
      const tests = [
        { name: 'ScreenScraper', url: 'https://api.screenscraper.fr/api2/' },
        { name: 'LaunchBox', url: 'https://gamesdb.launchbox-app.com/api/GetGames?name=Mario' },
        { name: 'TGDB', url: 'https://api.thegamesdb.net/v1/Games/ByGameName?apikey=&name=Mario' },
      ];
      const results = {};
      await Promise.all(tests.map(async t => {
        try {
          const r = await fetch(t.url, { method: 'GET', headers: { 'User-Agent': 'RetroVault/2.0' } });
          results[t.name] = { status: r.status, ok: r.status < 500 };
        } catch (e) {
          results[t.name] = { status: 0, ok: false, error: e.message };
        }
      }));
      return new Response(JSON.stringify({ ok: true, results, proxy: '/scraper-proxy?url=...' }), { status: 200, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' } });
    }

    // ════════════════════════════════════════════════════════════════════
    // BIOS SERVE — GET|HEAD /bios/:filename  serves from R2 bios/ prefix
    // HEAD is used by the frontend to probe which BIOS files exist in R2
    // without downloading them, so games auto-configure without manual uploads.
    // Cross-device BIOS access with correct COOP/COEP/CORP headers.
    // ════════════════════════════════════════════════════════════════════
    if (path.startsWith('/bios/') && (method === 'GET' || method === 'HEAD')) {
      const filename = decodeURIComponent(path.replace('/bios/', '')).replace(/\.\./g, '').replace(/^\/+/, '');
      if (!filename) {
        return new Response(JSON.stringify({ ok: false, error: 'Missing filename' }), {
          status: 400, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' }
        });
      }
      if (!env.ROM_BUCKET) {
        return new Response('ROM_BUCKET not configured', { status: 503, headers: corsHeaders(origin) });
      }
      try {
        // HEAD: use R2 head() — no body transfer, just metadata
        if (method === 'HEAD') {
          const obj = await env.ROM_BUCKET.head('bios/' + filename);
          if (!obj) {
            return new Response(null, { status: 404, headers: corsHeaders(origin) });
          }
          return new Response(null, {
            status: 200,
            headers: {
              ...corsHeaders(origin),
              'Content-Type': 'application/octet-stream',
              'Content-Length': String(obj.size || 0),
              'Cache-Control': 'public, max-age=86400',
              'Cross-Origin-Resource-Policy': 'cross-origin',
            },
          });
        }
        // GET: stream the full file
        const obj = await env.ROM_BUCKET.get('bios/' + filename);
        if (!obj) {
          return new Response('BIOS not found: ' + filename, { status: 404, headers: corsHeaders(origin) });
        }
        return new Response(obj.body, {
          status: 200,
          headers: {
            ...corsHeaders(origin),
            'Content-Type': 'application/octet-stream',
            'Cache-Control': 'public, max-age=86400',
            'Cross-Origin-Resource-Policy': 'cross-origin',
            'Cross-Origin-Embedder-Policy': 'require-corp',
            'Cross-Origin-Opener-Policy': 'same-origin',
          },
        });
      } catch (err) {
        return new Response('BIOS fetch error: ' + err.message, { status: 502, headers: corsHeaders(origin) });
      }
    }


    // ════════════════════════════════════════════════════════════════════
    // LB-SEARCH — GET /lb-search?name=GAMENAME
    // Reads meta/lb_index.json.gz from R2 (built by build_index.py).
    // Entry format: [name, db_id, platform, year, overview, developer, rating, genres]
    // ════════════════════════════════════════════════════════════════════
    if (path === '/lb-search') {
      const searchName = (url.searchParams.get('name') || '').trim();
      if (!searchName) {
        return new Response(JSON.stringify({ ok: false, error: 'Missing name' }), {
          status: 400, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' }
        });
      }
      if (!env.ROM_BUCKET) {
        return new Response(JSON.stringify({ ok: false, error: 'ROM_BUCKET not configured' }), {
          status: 503, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' }
        });
      }
      try {
        const obj = await env.ROM_BUCKET.get('meta/lb_index.json.gz');
        if (!obj) {
          return new Response(JSON.stringify({ ok: false, error: 'Index not found — upload meta/lb_index.json.gz to R2' }), {
            status: 404, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' }
          });
        }
        const compressed = await obj.arrayBuffer();
        const ds = new DecompressionStream('gzip');
        const writer = ds.writable.getWriter();
        const reader = ds.readable.getReader();
        writer.write(compressed);
        writer.close();
        const parts = [];
        while (true) {
          const { value, done } = await reader.read();
          if (done) break;
          if (value) parts.push(value);
        }
        const jsonText = new TextDecoder().decode(
          parts.reduce((acc, c) => { const m = new Uint8Array(acc.length + c.length); m.set(acc); m.set(c, acc.length); return m; }, new Uint8Array(0))
        );
        const games = JSON.parse(jsonText);
        function norm(s) {
          return (s||'').toLowerCase().replace(/[^a-z0-9 ]/g,' ').replace(/s+/g,' ').trim();
        }
        const needle = norm(searchName);
        let best = null, bestScore = -1;
        for (const g of games) {
          const gname = norm(g[0]);
          let score = 0;
          if (gname === needle) score = 100;
          else if (gname.startsWith(needle) || needle.startsWith(gname)) score = 80;
          else if (gname.includes(needle) || needle.includes(gname)) score = 60;
          else {
            const nw = needle.split(' '), gw = gname.split(' ');
            const shared = nw.filter(w => w.length > 2 && gw.includes(w)).length;
            if (shared > 0) score = Math.round((shared / Math.max(nw.length, gw.length)) * 50);
          }
          if (score > bestScore) { bestScore = score; best = g; }
        }
        if (!best || bestScore < 30) {
          return new Response(JSON.stringify({ ok: true, game: null, score: bestScore }), {
            status: 200, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json', 'Cache-Control': 'public, max-age=3600' }
          });
        }
        const [name, db_id, platform, year, overview, developer, rating, genres] = best;
        return new Response(JSON.stringify({
          ok: true, score: bestScore,
          game: { Name: name, DatabaseID: db_id, Platform: platform, ReleaseYear: year,
                  Overview: overview, Developer: developer, CommunityRating: rating,
                  Genres: genres, CoverUrl: db_id ? 'https://images.launchbox-app.com/' + db_id + '-01.jpg' : '' }
        }), {
          status: 200,
          headers: { ...corsHeaders(origin), 'Content-Type': 'application/json', 'Cache-Control': 'public, max-age=3600' }
        });
      } catch (err) {
        return new Response(JSON.stringify({ ok: false, error: 'lb-search error: ' + err.message }), {
          status: 500, headers: { ...corsHeaders(origin), 'Content-Type': 'application/json' }
        });
      }
    }

    // ════════════════════════════════════════════════════════════════════
    // DEFAULT — Serve the app HTML
    // ════════════════════════════════════════════════════════════════════
    const html = getHTML();
    return new Response(html, {
      headers: {
        'Content-Type': 'text/html; charset=UTF-8',
        'Cache-Control': 'no-cache, no-store, must-revalidate',
        'X-Content-Type-Options': 'nosniff',
        'X-Frame-Options': 'SAMEORIGIN',
        'Cross-Origin-Opener-Policy': 'same-origin',
        'Cross-Origin-Embedder-Policy': 'require-corp',
        ...corsHeaders(origin),
      },
    });
  },
};
